#include <bits/stdc++.h>using namespace std;#define int long long int#define all(x) x.begin(), x.end() const int N = 1000005;int spf[N]; void pre() {    iota(spf, spf + N, 0);    for (int i = 2; i * i < N; ++i)        if (spf[i] == i)            for (int j = i * i; j < N; j += i)                if (spf[j] == j) spf[j] = i;} void solve() {    int n; cin >> n;    vector<int> a(n);    for (auto &i : a) cin >> i;    if (is_sorted(all(a))) {         cout << "Bob\n";        return;    }    vector<int> v;    for (auto x : a) {        if (x == 1) {            v.push_back(1);            continue;        }        int p = spf[x], cnt = 0, y = x;        while (y % p == 0) y /= p, cnt++;        if (y != 1) {            cout << "Alice\n";            return;        }        while (cnt--) v.push_back(p);    }    cout << (is_sorted(all(v)) ? "Bob\n" : "Alice\n");}int32_t main() {    ios_base::sync_with_stdio(0); cin.tie(0);    pre();    int t = 1; cin >> t;    while (t--) solve();    return 0;}